WITH toDate('2024-07-01') AS peak_month, base AS ( SELECT OriginCode, DestCode, DepDelay FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month ), network AS ( SELECT count() AS network_flights, sum(greatest(DepDelay, 0)) AS network_delay_minutes FROM base ), origin_ranked AS ( SELECT OriginCode, count() AS flights, sum(greatest(DepDelay, 0)) AS delay_minutes FROM base GROUP BY OriginCode ), route_ranked AS ( SELECT concat(OriginCode, '-', DestCode) AS route, count() AS flights, sum(greatest(DepDelay, 0)) AS delay_minutes FROM base GROUP BY OriginCode, DestCode ), origin_top1 AS ( SELECT OriginCode AS top_origin, flights AS top_origin_flights, delay_minutes AS top_origin_delay_minutes FROM origin_ranked ORDER BY delay_minutes DESC, flights DESC LIMIT 1 ), route_top1 AS ( SELECT route AS top_route, flights AS top_route_flights, delay_minutes AS top_route_delay_minutes FROM route_ranked ORDER BY delay_minutes DESC, flights DESC LIMIT 1 ), top_origins AS ( SELECT sum(delay_minutes) AS top5_origin_delay_minutes, sum(flights) AS top5_origin_flights FROM (SELECT * FROM origin_ranked ORDER BY delay_minutes DESC, flights DESC LIMIT 5) ), top_routes AS ( SELECT sum(delay_minutes) AS top10_route_delay_minutes, sum(flights) AS top10_route_flights FROM (SELECT * FROM route_ranked ORDER BY delay_minutes DESC, flights DESC LIMIT 10) ) SELECT network_flights, network_delay_minutes, top_origin, top_origin_delay_minutes, round(top_origin_delay_minutes / network_delay_minutes * 100, 2) AS top_origin_delay_share_pct, top_origin_flights, round(top_origin_flights / network_flights * 100, 2) AS top_origin_flight_share_pct, top_route, top_route_delay_minutes, round(top_route_delay_minutes / network_delay_minutes * 100, 2) AS top_route_delay_share_pct, top_route_flights, round(top_route_flights / network_flights * 100, 2) AS top_route_flight_share_pct, top5_origin_delay_minutes, round(top5_origin_delay_minutes / network_delay_minutes * 100, 2) AS top5_origin_delay_share_pct, top5_origin_flights, round(top5_origin_flights / network_flights * 100, 2) AS top5_origin_flight_share_pct, top10_route_delay_minutes, round(top10_route_delay_minutes / network_delay_minutes * 100, 2) AS top10_route_delay_share_pct, top10_route_flights, round(top10_route_flights / network_flights * 100, 2) AS top10_route_flight_share_pct, (SELECT count() FROM origin_ranked) AS origin_count, (SELECT count() FROM route_ranked) AS route_count FROM network CROSS JOIN origin_top1 CROSS JOIN route_top1 CROSS JOIN top_origins CROSS JOIN top_routes
